method MinRotationsToEqual(s: string) returns (rotations: int)
    requires |s| > 0
    ensures rotations >= 0
{
    var doubled := s + s;
    var len := |s|;
    rotations := 0;
    var found := false;

    // Search for the first occurrence of s in doubled starting from position 1
    // (excluding the trivial match at position 0)
    for start := 1 to len
        invariant 1 <= start <= len
        invariant rotations >= 0
        // decreases len - start 
    {
        if forall i :: 0 <= i < len ==> s[i] == doubled[start + i] {
            rotations := start;
            found := true;
            break;
        }
    }

    // Since the string is non-empty, such a rotation must exist
    // and rotations > 0
    // No need for an explicit postcondition check as per the problem statement
}
